fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n <= 1 {
        return 0;
    }

    let mut total_cost: i64 = 0;

    // We need to ensure nums[i] + S_i <= nums[i+1] + S_{i+1}
    // where S_i is the total increment applied to nums[i].
    // This requires S_{i+1} - S_i >= nums[i] - nums[i+1].
    // To minimize the total cost (which equals the minimal necessary total increment S_{n-1}),
    // we find the sum of all positive required differences: max(0, nums[i] - nums[i+1]).

    for i in 0..(n - 1) {
        // Calculate the required difference: nums[i] - nums[i+1]
        let diff = nums[i] - nums[i+1];

        // If diff > 0, we need to compensate this difference by increasing elements
        // from index i+1 onwards relative to index i.
        if diff > 0 {
            total_cost += diff;
        }
    }

    total_cost
