fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n <= 1 {
        return 0;
    }

    let mut total_cost: i64 = 0;
    // i_prev represents I[i], the minimum total increase required for nums[i]. We start with I[0] = 0.
    let mut i_prev: i64 = 0; 

    // Iterate from i=0 to n-2 to determine I[i+1] based on I[i].
    for i in 0..(n - 1) {
        // We require: nums[i] + I[i] <= nums[i+1] + I[i+1]
        // I[i+1] - I[i] >= nums[i] - nums[i+1]

        let required_diff = nums[i] - nums[i+1];

        // Calculate the minimal required increase for the next element, I[i+1]
        // I[i+1] must be at least I[i] + required_diff, and I[i+1] must be non-negative.
        let i_next = (i_prev + required_diff).max(0);

        // The cost increase is max(0, I[i+1] - I[i]), which represents the net new increase 
        // starting at index i+1 that wasn't covered by operations ending at i.
        let cost_increase = (i_next - i_prev).max(0);

        total_cost += cost_increase;

        i_prev = i_next;
    }

    total_cost
}

